import React, { useEffect, useState } from 'react';

const CLIENT_ID = 'YOUR_CLIENT_ID';
const AUTH_URL = 'https://YOUR_AUTH_PROVIDER/oauth/authorize';
const REDIRECT_URI = 'http://localhost:3000/callback';
const SCOPE = 'YOUR_SCOPES';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  const handleLogin = () => {
    const url = `${AUTH_URL}?response_type=token&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&scope=${encodeURIComponent(SCOPE)}`;
    window.location.href = url;
  };

  return (
    <div>
      <h1>OAuth 2.0 Implicit Flow Example</h1>
      {!accessToken ? (
        <button onClick={handleLogin}>Login with OAuth</button>
      ) : (
        <div>
          <h2>Access Token</h2>
          <p>{accessToken}</p>
        </div>
      )}
    </div>
  );
};

const Callback = () => {
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash) {
      const token = new URLSearchParams(hash.replace('#', '?')).get('access_token');
      if (token) {
        setAccessToken(token);
        localStorage.setItem('access_token', token);
      }
    }
  }, []);

  return (
    <div>
      <h1>Callback Page</h1>
      {accessToken ? (
        <div>
          <h2>Access Token Retrieved</h2>
          <p>{accessToken}</p>
        </div>
      ) : (
        <p>No access token found.</p>
      )}
    </div>
  );
};

export { App, Callback };